  ('heelevel3-7c4986e7-moex-00095', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年初給予10位主管各1,000股認股權，並約定主管得於服務滿2年後，自X3年初 起1年內以每股$40的價格行使認股權，若給與日該公司普通股市價為每股$50，認股權之公允價 值為$15，估計兩年內總離職率為20%。請問X1年度該公司應認列之薪資費用為多少？', '["$120,000", "$100,000", "$60,000", "$40,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00096', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '某公司在甲銀行之現金活期存款為$750,000，其中$180,000 為去年向銀行借款時，銀行所要求之 補償性存款。此外，在乙銀行之存款帳戶則為透支$20,000。請問該公司於資產負債表中應報導之 現金金額為多少？', '["$550,000", "$570,000", "$730,000", "$850,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00097', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '關於不動產、廠房及設備，下列正確的敘述共有幾項？', '["採成本模式時，資產發生價值減損後仍須提列折舊", "評估資產減損時，可回收金額係指資產的公允價值減處分成本後餘額與使用價值，二者較高者", "採重估價模式時，仍須提列折舊與攤銷", "如符合分類為待出售條件之資產，應停止提列折舊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00098', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X4年7月1日與乙公司完成一項資產交易協議，甲公司該項換出資產X1年1月1日 原始取得成本為 $600,000，無殘值，耐用年限5年。交換日甲公司資產之公允價值為$200,000， 並另向乙公司收取現金$5,000。則有關該交換交易會計處理之敘述，何者錯誤？', '["若此筆交易具商業實質，則甲公司應認列換入資產價值為$195,000", "若此筆交易具商業實質，則甲公司應認處分利益$20,000", "若此筆交易不具商業實質，則甲公司應認列換入資產價值為$185,000", "若此筆交易不具商業實質，則甲公司毋須認列任何處分利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00099', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司紡織部門為一現金產生單位，部門內有A、B、C機器及商譽，本年年底之帳面金額分別為 $20,000、$30,000、$40,000及$10,000。因所屬產業環境變動，本年底該部門發生減損跡象，經估 計其可回收金額為$63,000，請問C機器應分攤之減損損失應為多少？', '["$12,000", "$14,800", "$9,000", "$16,444"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00100', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年10月1日賒銷商品$150,000，付款條件為2/10，1/20，n/30；X1年10月8日顧 客因商品瑕疵退回$20,000，並於隔日收到部分貨款之現金為$58,800，其餘貨款於 10 月 19 日收 現。請問該公司對於該批賒銷商品之總收現金額為多少？', '["$128,800", "$128,100", "$125,800", "$148,800"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
